class XorBase {
private:
	array<int, 21> a;    // 线性基基底
	array<int, 21> pos;  // 基底对应最晚出现的下标 
	static constexpr int MN = 20;
public:
	XorBase() {
		fill(a.begin(), a.end(), 0);
		fill(pos.begin(), pos.end(), 0);
	};

	// 插入新数
	void insert(int x, int idx) {
		if (!x)return;
		for (int i = MN; i >= 0; i--)
			if (x & (1ll << i)) {
				if (!a[i]) {
					// 线性基里没有 x，插入 x
					a[i] = x;
					pos[i] = idx;
					return;
				}
				// 【重点】：新下标放在高位，老下标去低位
				if (idx > pos[i]) {
					swap(idx, pos[i]);
					swap(x, a[i]);
				}
				x ^= a[i]; // 线性基里有 x
			}
	}

	// 查是否存在线性基内
	bool check(long long x, int L) {
		for (int i = MN; i >= 0; i--)
			if (x & (1ll << i))
				if (!a[i])return false;
				else {
					if (pos[i] >= L)x ^= a[i];
					else return false;
				}
		return true;
	}
};
